<?php
/**
 * Dernek Plugin Installer - run once then auto-deletes
 * Access: https://bitebimuv.org/dernek-installer.php
 */
if (php_sapi_name() !== 'cli' && !isset($_GET['run'])) {
    die('Add ?run=1 to execute');
}

$base = __DIR__ . '/wp-content/plugins/dernek-project-sync';
$files = [
    "dernek-project-sync.php" => "",
    "includes/class-rest-api.php" => "",
    "includes/class-post-type.php" => "",
    "includes/class-admin-widget.php" => "",
    "includes/class-social-scheduler.php" => "",
    "includes/class-content-pipeline.php" => "",
    "includes/class-notebooklm-bridge.php" => "",
    "public/shortcode.php" => ""
];

// Create directories
foreach (['', '/includes', '/public'] as $sub) {
    $dir = $base . $sub;
    if (!is_dir($dir)) {
        mkdir($dir, 0755, true);
        echo "Created: $dir\n";
    } else {
        echo "Exists:  $dir\n";
    }
}

// Write files
$ok = true;
foreach ($files as $rel => $b64) {
    $path = $base . '/' . $rel;
    $content = base64_decode($b64);
    if (file_put_contents($path, $content) !== false) {
        echo "Written: $rel (" . strlen($content) . " bytes)\n";
    } else {
        echo "FAILED:  $rel\n";
        $ok = false;
    }
}

// Self-delete
unlink(__FILE__);
echo "\nInstaller deleted itself.\n";
echo $ok ? "\n=== SUCCESS ===\n" : "\n=== SOME FAILURES ===\n";
